items.mermaid:
flowchart TB
  Start(["Read the problem"]) --> Q1{"Sub-array / sub-string?"}
  Q1 -- yes --> SW["Sliding window"]
  Q1 -- no  --> Q2{"Pair / partition on a sequence?"}
  Q2 -- yes --> TP["Two-pointer"]
  Q2 -- no  --> Q3{"Tree / graph / grid?"}
  Q3 -- yes --> Q3a{"Unweighted shortest path?"}
  Q3a -- yes --> BFS["BFS"]
  Q3a -- no  --> Q3b{"Weighted shortest path (non-negative)?"}
  Q3b -- yes --> DJ["Dijkstra (heap)"]
  Q3b -- no  --> DFS["DFS / topological / union-find"]
  Q3 -- no  --> Q4{"Top-k / scheduling / merge?"}
  Q4 -- yes --> HP["Heap (priority queue)"]
  Q4 -- no  --> Q5{"Optimization with overlapping sub-problems?"}
  Q5 -- yes --> DP["Dynamic programming"]
  Q5 -- no  --> Q6{"Local choice = global optimum?"}
  Q6 -- yes --> GR["Greedy + sort"]
  Q6 -- no  --> BT["Backtracking (last resort)"]
